function TitlesArray() {
  return [
    {
      id: 'three-card-past',
      title: 'Past',
    },
    {
      id: 'three-card-present',
      title: 'Present',
    },
    {
      id: 'three-card-future',
      title: 'Future',
    }
  ];
}

export default TitlesArray;
